app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Login: http://localhost:${PORT}/login`);
  console.log(`Start OAuth: http://localhost:${PORT}/auth/login?return_url=/dashboard`);
});

module.exports = app;